module mux16to1 (
    input [15:0] input_data,  // 16 data inputs
    input [3:0] select,    // 4 selection lines
    output reg out         // Output
);
    always @(*) begin
        case (select)
            4'b0000: out = input_data[0];
            4'b0001: out = input_data[1];
            4'b0010: out = input_data[2];
            4'b0011: out = input_data[3];
            4'b0100: out = input_data[4];
            4'b0101: out = input_data[5];
            4'b0110: out = input_data[6];
            4'b0111: out = input_data[7];
            4'b1000: out = input_data[8];
            4'b1001: out = input_data[9];
            4'b1010: out = input_data[10];
            4'b1011: out = input_data[11];
            4'b1100: out = input_data[12];
            4'b1101: out = input_data[13];
            4'b1110: out = input_data[14];
            4'b1111: out = input_data[15];
            default: out = 1'b0; // default case
        endcase
    end
endmodule
